patch:
diff --git a/llvm/lib/Analysis/ValueTracking.cpp b/llvm/lib/Analysis/ValueTracking.cpp
index 973943790c0a..3c74567b9107 100644
--- a/llvm/lib/Analysis/ValueTracking.cpp
+++ b/llvm/lib/Analysis/ValueTracking.cpp
@@ -8209,6 +8209,11 @@ isImpliedCondOperands(CmpInst::Predicate Pred, const Value *ALHS,
     if (isTruePredicate(CmpInst::ICMP_ULE, BLHS, ALHS, DL, Depth) &&
         isTruePredicate(CmpInst::ICMP_ULE, ARHS, BRHS, DL, Depth))
       return true;
+    // (add a, b) ult a implies (add a, b) ult b (unsigned overflow)
+    if (Pred == CmpInst::ICMP_ULT && ALHS == BLHS &&
+        (match(ALHS, m_Add(m_Specific(ARHS), m_Specific(BRHS))) ||
+         match(ALHS, m_Add(m_Specific(BRHS), m_Specific(ARHS)))))
+      return true;
     return std::nullopt;

   case CmpInst::ICMP_UGT:
@@ -8216,6 +8221,11 @@ isImpliedCondOperands(CmpInst::Predicate Pred, const Value *ALHS,
     if (isTruePredicate(CmpInst::ICMP_ULE, ALHS, BLHS, DL, Depth) &&
         isTruePredicate(CmpInst::ICMP_ULE, BRHS, ARHS, DL, Depth))
       return true;
+    // (add a, b) uge a implies (add a, b) uge b (no unsigned overflow)
+    if (Pred == CmpInst::ICMP_UGE && ALHS == BLHS &&
+        (match(ALHS, m_Add(m_Specific(ARHS), m_Specific(BRHS))) ||
+         match(ALHS, m_Add(m_Specific(BRHS), m_Specific(ARHS)))))
+      return true;
     return std::nullopt;
   }
 }
@@ -8295,6 +8305,18 @@ static std::optional<bool> isImpliedCondICmps(const ICmpInst *LHS,
   if (LPred == RPred)
     return isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth);

+  // If LPred is the inverse of RPred, then check if LPred L0,L1 implies
+  // LPred R0,R1. If so, then LPred L0,L1 implies !(RPred R0,R1), i.e.,
+  // the RHS is false.
+  if (LPred == ICmpInst::getInversePredicate(RPred))
+    if (auto Res = isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth))
+      if (*Res)
+        return false;
+
+  return std::nullopt;
+  if (LPred == RPred)
+    return isImpliedCondOperands(LPred, L0, L1, R0, R1, DL, Depth);
+
   return std::nullopt;
 }
